            if (!isPowerMenu) {
                val cls = event.className?.toString() ?: ""
                if (cls.contains("GlobalActions", ignoreCase = true) || cls.contains("Power", ignoreCase = true)) {
                    isPowerMenu = true
                    DynamicEntry.log("⚠️ Fallback Matched Class: $cls")
                }
